// El JSON de Apify viene en el body del webhook
// Puede ser un array directo o estar dentro de body
const raw = $json.body || $json;
const results = Array.isArray(raw) ? raw : [raw];

const SCORE_MINIMO = 7;
const places = [];

for (const place of results) {
  if (!place.title || place.permanentlyClosed) continue;

  // Construir direccion desde street + city
  const direccion = [place.street, place.city, place.state, place.countryCode]
    .filter(Boolean).join(', ');

  // Extraer email
  const email = (place.emails || [])[0]?.email
    || (place.emails || [])[0]
    || '';

  places.push({
    json: {
      place_id:  place.placeId || place.title,
      nombre:    place.title || '',
      tipo:      place.categoryName || (place.categories||[])[0] || '',
      direccion: direccion || place.address || '',
      telefono:  (place.phone||place.phoneUnformatted||'').replace(/\s/g,''),
      website:   place.website || '',
      email:     email,
      rating:    place.totalScore || 0,
      reviews:   place.reviewsCount || 0,
      maps_url:  place.url || '',
      fuente:    'Apify/Google Maps',
      scoreMinimo: SCORE_MINIMO
    }
  });
}

return places;

const prev = $input.item.json;
const texto = $json.message?.content || $json.choices?.[0]?.message?.content || $json.content || '{}';

let cal;
try {
  const match = texto.match(/\{[\s\S]*\}/);
  cal = match ? JSON.parse(match[0]) : {};
} catch(e) {
  cal = { score: 0, motivo: 'Error', canal_recomendado: 'email', problema_principal: '' };
}

return [{
  json: {
    ...prev,
    score:              cal.score || 0,
    motivo_score:       cal.motivo || '',
    canal_recomendado:  cal.canal_recomendado || 'email',
    problema_principal: cal.problema_principal || '',
    status:             'calificado',
    fecha_creado:       new Date().toISOString().split('T')[0]
  }
}];

